-----------------------------------------------------------------
function ItemIconNew:OnInitTrans()
    local iconInst = self._iconInst
    self._uiTypeTrans = CS.FindTrans(iconInst, "TypeImg")
    self._uiTimeImgTrans = CS.FindTrans(iconInst, "TimeImg")
    self._uiShiftImgTrans = CS.FindTrans(iconInst, "ShiftImg")
    self._uiGouTrans = CS.FindTrans(iconInst, "GouImg")
    self._uiMaskTrans = CS.FindTrans(iconInst, "MaskImg")
    self._uiLockTrans = CS.FindTrans(iconInst, "LockImg")
    self._uiNewTrans = CS.FindTrans(iconInst, "NewImg")

    self._uiStarTrans = CS.FindTrans(iconInst, "StarList")

    self._uiNumBgTrans = CS.FindTrans(iconInst, "MaskNumBg")
    self._uiNumTxtTrans = CS.FindTrans(self._uiNumBgTrans, "ItemNum")

    self._activeTran = CS.FindTrans(iconInst, "activeBg")

    self:InitStartList()
end

-----------------------------------------------------------------
function ItemIconNew:SetData(refId, itemNum, isShowUnlimited)
    local refId = refId

    self._refId = refId

    self._itemNum = itemNum

    local num = itemNum
    if not num then
        num = gModelItem and gModelItem:GetNumByRefId(refId) or 0
    end

    local race = nil
    local star = 0
    local iconPath = nil
    local iconBgPath = nil
    local itemName = nil
    local itemColor = nil
    local minIcon = nil

    local itemRef = self:GetItemRef(refId)
    if itemRef then
        race = itemRef.race
        star = itemRef.star
        itemName = ccLngText(itemRef.name)
        minIcon = itemRef.minIcon

        iconPath = itemRef.icon

        local quaId = itemRef.quality
        local qualityRef = self:GetItemQualityRef(quaId)

        if qualityRef then
            iconBgPath = qualityRef.iconBg
            local color = qualityRef.nameColor
            if color then
                itemColor = LUtil.ColorByHex(color)
            end
        end
    end

    self._displayName = itemName
    self._displayColor = itemColor
    self._displayTypeIcon = race
    self._displayStar = star

    self._displayShowIcon = iconPath
    self._displayShowIconBg = iconBgPath

    self._displayMinIcon = minIcon
    self._displayShowUnlimited = isShowUnlimited
    num = LUtil.NumberCoversion(num)
    self._displayNum = num
end

function ItemIconNew:ChangeIconPath(iconPath)
    self._displayShowIcon = iconPath
end

function ItemIconNew:GetNameData()
    return self._displayName, self._displayColor
end

-----------------------------------------------------------------
function ItemIconNew:UpdateTypeImage()
    local typeImg = self._displayTypeIcon
    if not string.isempty(typeImg) then
        self:SetCommonImg(self._uiTypeTrans, typeImg)
        if not self._uiTypeTrans.gameObject.activeSelf then
            CS.ShowObject(self._uiTypeTrans, true)
        end
    else
        if self._uiTypeTrans.gameObject.activeSelf then
            CS.ShowObject(self._uiTypeTrans, false)
        end
    end
end
-----------------------------------------------------------------
function ItemIconNew:UpdateMinIconImage()
    local minIconImg = self._displayMinIcon
    if not string.isempty(minIconImg) then
        self:SetCommonImg(self._uiTimeImgTrans, minIconImg, nil, true)
        if not self._uiTimeImgTrans.gameObject.activeSelf then
            CS.ShowObject(self._uiTimeImgTrans, true)
        end
    else
        if self._uiTimeImgTrans.gameObject.activeSelf then
            CS.ShowObject(self._uiTimeImgTrans, false)
        end
    end
end
-----------------------------------------------------------------
function ItemIconNew:SetNumUIVisible()
    local b = self._hideNum and self._hideNum or false
    b = not b
    if self._uiNumTxtTrans.gameObject.activeSelf ~= b then
        CS.ShowObject(self._uiNumTxtTrans, b)
    end
end

function ItemIconNew:SetBgUIVisible()
    local b = self._hideBg and self._hideBg or false
    b = not b
    if self._uiIconBgTrans.gameObject.activeSelf ~= b then
        CS.ShowObject(self._uiIconBgTrans, b)
    end
end

function ItemIconNew:SetFontSize(v)
    self._fontSize = v
    self:UpdateNumTextSize()
end

function ItemIconNew:UpdateNumTextSize()
    self._fontSize = self._fontSize or 20
    LxUiHelper.SetTextFontSize(self._uiNumTxtTrans, self._fontSize)
end

function ItemIconNew:UpdateNumText()
    if self._hideNum then
        return
    end
    local num = self._displayNum
    if not self._showNeedNumStatus then
        if (num == "-1" or num == "0") then
            num = ""
        elseif (num == "-2") and  self._displayShowUnlimited then
            num = ccClientText(44241)
        end
        self:SetXUIText(self._uiNumTxtTrans, num)
    else
        local allNum = gModelItem and gModelItem:GetNumByRefId(self._refId) or 0
        local color
        if self._itemNum > allNum then
            color = "ff5151FF"
        else
            color = "0fb93fFF"
        end
        allNum = LUtil.NumberCoversion(allNum)
        local str
        if not self._showTypeStr then
            str = string.format("<color=#%s>%s</color>/%s", color, allNum, num)
        else
            str = string.format("<color=#%s>%s</color>", color, num)
        end
        self:SetXUIText(self._uiNumTxtTrans, str)
    end
end

function ItemIconNew:SetShowNew(status)
    status = status or false
    local show = self._showNew or false
    if show == status then
        return
    end
    self._showNew = status

    self:UpdateNewImg()
end

function ItemIconNew:UpdateNewImg()
    local show = self._showNew or false
    CS.ShowObject(self._uiNewTrans, show)
end

