function ItemIconNew:SetShowGouImg(b)
    b = b or false and true
    self:ShowGouImg(b)
end

function ItemIconNew:ShowGouImg(b)
    if self._showGou == b then
        return
    end
    self._showGou = b
    self._showMask = b

    self:UpdateCheckVisible()
    self:UpdateMaskVisible()
end

function ItemIconNew:GetGouImg()
    return self._uiGouTrans
end

function ItemIconNew:SetShowLock(bLock)
    bLock = bLock or false and true

    self:ShowLock(bLock)
end

function ItemIconNew:ShowLock(bLock)
    bLock = bLock or false and true

    if self._bShowLock == bLock then
        return
    end
    self._bShowLock = bLock
    self._showMask = bLock

    self:UpdateLockVisible()
    self:UpdateMaskVisible()
end

function ItemIconNew:SetItemNum(num)
    self._itemNum = num

    num = LUtil.NumberCoversion(num)
    self._displayNum = num

    if not self:IsIconValid() then
        return
    end
    self:UpdateNumText()
end

function ItemIconNew:SetItemNumStr(numStr)
    if not numStr or string.isempty(numStr) then
        return
    end
    self._displayNum = numStr
    if not self:IsIconValid() then
        return
    end
    self:UpdateNumText()
end

function ItemIconNew:SetHideNum(isHide)
    self._hideNum = isHide

    if not self:IsIconValid() then
        return
    end
    self:SetNumUIVisible()
end

function ItemIconNew:EnableShowNum(bShow)
    self._hideNum = not bShow
end

function ItemIconNew:EnableShowBg(bShow)
    self._hideBg = not bShow
end

function ItemIconNew:ShowNeedNumStatus(b, showType)
    self._showNeedNumStatus = b
    self._showTypeStr = showType
end

