function ItemIconNew:GetItemRef(refId)
    local itemRef = GameTable.PlayerItemRef[refId]
    if LOG_INFO_ENABLED then
        if not itemRef then
            LogError("配置表ItemRef[refId]为空, refId = " .. refId)
        end
    end

    --地区屏蔽
    if gModelFunctionOpen:CheckRefDisable(ModelFunctionOpen.ITEM, refId) then
        return
    end

    return itemRef
end

return ItemIconNew